{"parts":[{"tool_name":"read_file","content":["import React, { useState, useCallback, useEffect } from "react";
import { usePlaidLink } from "react-plaid-link";
import { Toaster, toast } from "sonner";
import SpendingDashboard from "../../components/SpendingDashboard";
import NetWorthCard from "../../components/NetWorthCard";
import { BudgetView } from "../../components/BudgetView";
import MatchDayTracker from "../../components/MatchDayTracker";
import { getArtetaQuote } from "../../lib/arteta-quotes";
import { Skeleton, SkeletonCard, SkeletonTableRow } from "../../components/ui/skeleton";

type AccountType = {
  account_id: string;
  name: string;
  type: string;
  subtype: string;
  balances: {
    current: number;
    available: number | null;
  };
};

type Transaction = {
  transaction_id: string;
  date: string;
  name: string;
  amount: number;
  category: string[];
};

type Holding = {
  holding_id?: string;
  security_id: string;
  quantity: number;
  institution_value: number;
};

type Security = {
  security_id: string;
  name: string;
  ticker_symbol: string | null;
  type: string;
};

type TabType = 'dashboard' | 'budget' | 'matchday' | 'accounts' | 'transactions' | 'investments' | 'liabilities' | 'networth';

const TAB_CONFIG: { id: TabType; icon: string; label: string }[] = [
  { id: 'dashboard', icon: '📊', label: 'Dashboard' },
  { id: 'accounts', icon: '🏦', label: 'Accounts' },
  { id: 'budget', icon: '🎯', label: 'Budget' },
  { id: 'transactions', icon: '💳', label: 'Transactions' },
  { id: 'investments', icon: '📈', label: 'Investments' },
  { id: 'liabilities', icon: '📉', label: 'Liabilities' },
  { id: 'networth', icon: '🏆', label: 'Net Worth' },
  { id: 'matchday', icon: '⚽', label: 'Match Day' },
];

export default function PlaidPFMDemo() {
  const [linkToken, setLinkToken] = useState<string | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [accounts, setAccounts] = useState<AccountType[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [holdings, setHoldings] = useState<Holding[]>([]);
  const [securities, setSecurities] = useState<Security[]>([]);
  const [liabilities, setLiabilities] = useState<any>(null);
  const [activeTab, setActiveTab] = useState<TabType>('dashboard');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Check existing connection status on mount
  useEffect(() => {
    const checkStatus = async () => {
      try {
        const res = await fetch('/api/status');
        const data = await res.json();
        if (data.connected) {
          setIsConnected(true);
          fetchAccounts();
        }
      } catch (err) {
        // Ignore - not connected
      }
    };
    checkStatus();
  }, []);

  // Create link token on mount
  useEffect(() => {
    const createLinkToken = async () => {
      try {
        const res = await fetch('/api/plaid/create-link-token', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({}),
        });
        const data = await res.json();
        if (data.link_token) {
          setLinkToken(data.link_token);
        } else {
          setError(data.error?.error_message || 'Failed to create link token');
        }
      } catch (err) {
        setError('Failed to initialize Plaid Link');
      }
    };
    createLinkToken();
  }, []);

  const onSuccess = useCallback(async (publicToken: string) => {
    setLoading(true);
    setError(null);
    try {
      // Exchange public token
      const exchangeRes = await fetch('/api/plaid/exchange-token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ public_token: publicToken }),
      });
      const exchangeData = await exchangeRes.json();

      if (exchangeData.success) {
        setIsConnected(true);
        toast.success("Account Connected!", {
          description: getArtetaQuote('goal_scored'),
          icon: "⚽",
        });
        // Fetch accounts
        await fetchAccounts();
        // Automatically sync transactions for the dashboard
        await syncTransactions();
      } else {
        setError(exchangeData.error?.error_message || 'Failed to connect account');
        toast.error("Connection Failed", {
          description: getArtetaQuote('budget_loss'),
        });
      }
    } catch (err) {
      setError('Failed to connect account');
      toast.error("Connection Failed");
    }
    setLoading(false);
  }, []);

  const { open, ready } = usePlaidLink({
    token: linkToken,
    onSuccess,
  });

  const fetchAccounts = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/plaid/accounts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      });
      const data = await res.json();
      if (data.accounts) {
        setAccounts(data.accounts);
      }
    } catch (err) {
      setError('Failed to fetch accounts');
    }
    setLoading(false);
  };

  const syncTransactions = async () => {
    try {
      // Sync last 90 days of transactions for dashboard analytics
      const startDate = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
      await fetch('/api/plaid/transactions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ startDate }),
      });
    } catch (err) {
      console.error('Failed to sync transactions:', err);
    }
  };

  const fetchTransactions = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/plaid/transactions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      });
      const data = await res.json();
      if (data.transactions) {
        setTransactions(data.transactions);
      } else {
        setError(data.error?.error_message || data.error || 'Failed to fetch transactions');
      }
    } catch (err) {
      setError('Failed to fetch transactions');
    }
    setLoading(false);
  };

  const fetchInvestments = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/plaid/investments/holdings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      });
      const data = await res.json();
      if (data.holdings) {
        setHoldings(data.holdings);
        setSecurities(data.securities || []);
      } else {
        setError(data.error?.error_message || data.error || 'No investment data (account may not have investments)');
      }
    } catch (err) {
      setError('Failed to fetch investments');
    }
    setLoading(false);
  };

  const fetchLiabilities = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/plaid/liabilities', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({}),
      });
      const data = await res.json();
      if (data.liabilities) {
        setLiabilities(data.liabilities);
      } else {
        setError(data.error?.error_message || data.error || 'No liability data');
      }
    } catch (err) {
      setError('Failed to fetch liabilities');
    }
    setLoading(false);
  };

  const getSecurityName = (securityId: string) => {
    const security = securities.find(s => s.security_id === securityId);
    return security?.name || security?.ticker_symbol || securityId;
  };

  const handleTabChange = (tab: TabType) => {
    setActiveTab(tab);
    setError(null);
    if (tab === 'transactions' && transactions.length === 0) fetchTransactions();
    if (tab === 'investments' && holdings.length === 0) fetchInvestments();
    if (tab === 'liabilities' && !liabilities) fetchLiabilities();
  };

  return (
    <div className="min-h-screen bg-[#0d0d0d] text-white p-4 sm:p-8">
      <Toaster 
        position="top-right" 
        theme="dark"
        toastOptions={{
          style: {
            background: '#1a1a1a',
            border: '1px solid rgba(239, 1, 7, 0.2)',
            color: '#fff',
          },
        }}
      />

      <div className="max-w-5xl mx-auto">
        {/* Arsenal-Style Header */}
        <div className="mb-8 border-b border-[#EF0107]/20 pb-6">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-[#EF0107] rounded-lg flex items-center justify-center shadow-lg shadow-[#EF0107]/20">
              <span className="text-2xl">🔴</span>
            </div>
            <div>
              <h1 className="text-2xl sm:text-3xl font-bold tracking-tight">
                <span className="text-[#EF0107]">ARSENAL</span> PFM
              </h1>
              <p className="text-[#9C824A] text-sm font-medium">Victory Through Financial Stability</p>
            </div>
          </div>
        </div>

        {error && (
          <div className="bg-[#EF0107]/20 border border-[#EF0107] text-[#ff8589] px-4 py-3 rounded-lg mb-6 animate-in fade-in-50 duration-200">
            <div className="flex items-center gap-2">
              <span>😤</span>
              <span>{error}</span>
            </div>
          </div>
        )}

        {!isConnected ? (
          <div className="bg-zinc-900 rounded-lg p-8 text-center border border-[#EF0107]/20 card-hover">
            <div className="text-6xl mb-4 animate-bounce-subtle">⚽</div>
            <h2 className="text-xl font-semibold mb-4">Connect Your Bank Account</h2>
            <p className="text-zinc-400 mb-2">
              Use Plaid's secure connection to link your accounts. In Sandbox mode, use:
            </p>
            <code className="bg-zinc-800 px-3 py-1.5 rounded mt-2 inline-block border border-[#9C824A]/30 text-[#9C824A]">
              user_good / pass_good
            </code>
            <p className="text-zinc-500 text-sm mt-4 italic">
              "{getArtetaQuote('welcome')}"
            </p>
            <button
              onClick={() => open()}
              disabled={!ready || loading}
              className="mt-6 bg-[#EF0107] hover:bg-[#b30006] disabled:bg-zinc-700 disabled:cursor-not-allowed px-6 py-3 rounded-lg font-medium transition-all hover:shadow-lg hover:shadow-[#EF0107]/30 focus-ring-arsenal"
            >
              {loading ? (
                <span className="flex items-center gap-2">
                  <span className="arsenal-spinner w-4 h-4" />
                  Connecting...
                </span>
              ) : (
                '🔴 Connect with Plaid'
              )}
            </button>
          </div>
        ) : (
          <>
            {/* Arsenal-Styled Tabs - Mobile Scrollable */}
            <div className="tab-bar-scroll flex gap-1 mb-6 border-b border-zinc-800 pb-0">
              {TAB_CONFIG.map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => handleTabChange(tab.id)}
                  title={tab.label}
                  className={`px-2 sm:px-4 py-3 transition whitespace-nowrap border-b-2 -mb-[2px] focus-ring-arsenal text-sm sm:text-base ${
                    activeTab === tab.id
                      ? 'border-[#EF0107] text-white bg-zinc-900/50'
                      : 'border-transparent text-zinc-400 hover:text-white hover:bg-zinc-800/30'
                  }`}
                >
                  <span className="sm:mr-1.5">{tab.icon}</span>
                  <span className="hidden sm:inline">{tab.label}</span>
                </button>
              ))}
            </div>

            {/* Tab Content with Animation */}
            <div className="tab-content">
              {/* Dashboard Tab */}
              {activeTab === 'dashboard' && (
                <div className="space-y-6">
                  <NetWorthCard />
                  <SpendingDashboard />
                </div>
              )}

              {/* Budget Tab */}
              {activeTab === 'budget' && <BudgetView />}

              {/* Match Day Tab */}
              {activeTab === 'matchday' && <MatchDayTracker />}

              {/* Accounts Tab */}
              {activeTab === 'accounts' && (
                <>
                  {loading ? (
                    <div className="grid gap-4">
                      {Array.from({ length: 3 }).map((_, i) => (
                        <div key={i} className="bg-zinc-900 rounded-lg p-4 border border-[#EF0107]/10">
                          <div className="flex justify-between items-start">
                            <div>
                              <Skeleton className="h-5 w-32 mb-2" />
                              <Skeleton className="h-4 w-24" />
                            </div>
                            <div className="text-right">
                              <Skeleton className="h-6 w-24 mb-1" />
                              <Skeleton className="h-4 w-20" />
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="grid gap-4">
                      {accounts.map((account) => (
                        <div key={account.account_id} className="bg-zinc-900 rounded-lg p-4 border border-[#EF0107]/10 hover:border-[#EF0107]/30 transition card-hover">
                          <div className="flex justify-between items-start">
                            <div>
                              <h3 className="font-semibold">{account.name}</h3>
                              <p className="text-zinc-400 text-sm capitalize">{account.type} • {account.subtype}</p>
                            </div>
                            <div className="text-right">
                              <p className="text-xl font-bold text-[#9C824A] stat-number">${account.balances.current?.toLocaleString() ?? '—'}</p>
                              {account.balances.available && (
                                <p className="text-zinc-400 text-sm">Available: ${account.balances.available.toLocaleString()}</p>
                              )}
                            </div>
                          </div>
                        </div>
                      ))}
                      {accounts.length === 0 && (
                        <div className="text-center py-12 text-zinc-400 bg-zinc-900 rounded-lg border border-[#EF0107]/10">
                          <div className="text-4xl mb-3">🏦</div>
                          <p>No accounts found</p>
                          <p className="text-sm text-zinc-500 mt-1 italic">"{getArtetaQuote('empty')}"</p>
                        </div>
                      )}
                    </div>
                  )}
                </>
              )}

              {/* Transactions Tab */}
              {activeTab === 'transactions' && (
                <>
                  {loading ? (
                    <div className="bg-zinc-900 rounded-lg overflow-hidden border border-[#EF0107]/10">
                      <table className="w-full">
                        <thead className="bg-zinc-800">
                          <tr>
                            <th className="text-left p-3">Date</th>
                            <th className="text-left p-3">Description</th>
                            <th className="text-left p-3">Category</th>
                            <th className="text-right p-3">Amount</th>
                          </tr>
                        </thead>
                        <tbody>
                          {Array.from({ length: 8 }).map((_, i) => (
                            <SkeletonTableRow key={i} columns={4} />
                          ))}
                        </tbody>
                      </table>
                    </div>
                  ) : (
                    <div className="bg-zinc-900 rounded-lg overflow-hidden border border-[#EF0107]/10 mobile-table-scroll">
                      <table className="w-full">
                        <thead className="bg-zinc-800">
                          <tr>
                            <th className="text-left p-3 text-sm font-medium text-zinc-300">Date</th>
                            <th className="text-left p-3 text-sm font-medium text-zinc-300">Description</th>
                            <th className="text-left p-3 text-sm font-medium text-zinc-300">Category</th>
                            <th className="text-right p-3 text-sm font-medium text-zinc-300">Amount</th>
                          </tr>
                        </thead>
                        <tbody>
                          {transactions.slice(0, 20).map((tx) => (
                            <tr key={tx.transaction_id} className="border-t border-zinc-800 hover:bg-zinc-800/30 transition">
                              <td className="p-3 text-zinc-400 text-sm">{tx.date}</td>
                              <td className="p-3 text-sm">{tx.name}</td>
                              <td className="p-3 text-zinc-400 text-sm">{tx.category?.join(', ') || '—'}</td>
                              <td className={`p-3 text-right font-medium text-sm stat-number ${tx.amount > 0 ? 'text-[#EF0107]' : 'text-[#9C824A]'}`}>
                                {tx.amount > 0 ? '-' : '+'}${Math.abs(tx.amount).toFixed(2)}
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                      {transactions.length === 0 && (
                        <div className="text-center py-12 text-zinc-400">
                          <div className="text-4xl mb-3">💳</div>
                          <p>No transactions found</p>
                          <p className="text-sm text-zinc-500 mt-1">Time to make some moves! 🔥</p>
                        </div>
                      )}
                    </div>
                  )}
                </>
              )}

              {/* Investments Tab */}
              {activeTab === 'investments' && (
                <>
                  {loading ? (
                    <div className="bg-zinc-900 rounded-lg overflow-hidden border border-[#EF0107]/10">
                      <table className="w-full">
                        <thead className="bg-zinc-800">
                          <tr>
                            <th className="text-left p-3">Security</th>
                            <th className="text-right p-3">Quantity</th>
                            <th className="text-right p-3">Value</th>
                          </tr>
                        </thead>
                        <tbody>
                          {Array.from({ length: 5 }).map((_, i) => (
                            <SkeletonTableRow key={i} columns={3} />
                          ))}
                        </tbody>
                      </table>
                    </div>
                  ) : (
                    <div className="bg-zinc-900 rounded-lg overflow-hidden border border-[#EF0107]/10 mobile-table-scroll">
                      <table className="w-full">
                        <thead className="bg-zinc-800">
                          <tr>
                            <th className="text-left p-3 text-sm font-medium text-zinc-300">Security</th>
                            <th className="text-right p-3 text-sm font-medium text-zinc-300">Quantity</th>
                            <th className="text-right p-3 text-sm font-medium text-zinc-300">Value</th>
                          </tr>
                        </thead>
                        <tbody>
                          {holdings.map((holding, idx) => (
                            <tr key={idx} className="border-t border-zinc-800 hover:bg-zinc-800/30 transition">
                              <td className="p-3 text-sm">{getSecurityName(holding.security_id)}</td>
                              <td className="p-3 text-right text-sm stat-number">{holding.quantity.toFixed(4)}</td>
                              <td className="p-3 text-right text-[#9C824A] font-medium text-sm stat-number">${holding.institution_value.toLocaleString()}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                      {holdings.length === 0 && (
                        <div className="text-center py-12 text-zinc-400">
                          <div className="text-4xl mb-3">📈</div>
                          <p>No investment holdings found</p>
                          <p className="text-sm text-zinc-500 mt-1">Build that squad! 💪</p>
                        </div>
                      )}
                    </div>
                  )}
                </>
              )}

              {/* Liabilities Tab */}
              {activeTab === 'liabilities' && (
                <>
                  {loading ? (
                    <div className="space-y-4">
                      {Array.from({ length: 2 }).map((_, i) => (
                        <div key={i} className="bg-zinc-900 rounded-lg p-4 border border-[#EF0107]/20">
                          <Skeleton className="h-5 w-28 mb-4" />
                          <div className="space-y-3">
                            {Array.from({ length: 3 }).map((_, j) => (
                              <div key={j} className="flex justify-between">
                                <Skeleton className="h-4 w-32" />
                                <Skeleton className="h-4 w-20" />
                              </div>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {liabilities?.credit && liabilities.credit.length > 0 && (
                        <div className="bg-zinc-900 rounded-lg p-4 border border-[#EF0107]/20 card-hover">
                          <h3 className="font-semibold mb-3 text-[#EF0107] flex items-center gap-2">
                            <span>💳</span> Credit Cards
                          </h3>
                          {liabilities.credit.map((card: any, idx: number) => (
                            <div key={idx} className="border-t border-zinc-800 pt-3 mt-3 first:border-0 first:pt-0 first:mt-0">
                              <div className="flex justify-between text-sm">
                                <span className="text-zinc-400">APR</span>
                                <span className="text-[#EF0107] stat-number">{(card.aprs?.[0]?.apr_percentage || 0).toFixed(2)}%</span>
                              </div>
                              <div className="flex justify-between text-zinc-400 text-sm">
                                <span>Last Statement Balance</span>
                                <span className="stat-number">${card.last_statement_balance?.toLocaleString() || '—'}</span>
                              </div>
                              <div className="flex justify-between text-zinc-400 text-sm">
                                <span>Minimum Payment</span>
                                <span className="stat-number">${card.minimum_payment_amount?.toLocaleString() || '—'}</span>
                              </div>
                            </div>
                          ))}
                        </div>
                      )}

                      {liabilities?.student && liabilities.student.length > 0 && (
                        <div className="bg-zinc-900 rounded-lg p-4 border border-[#063672]/30 card-hover">
                          <h3 className="font-semibold mb-3 text-[#063672] flex items-center gap-2">
                            <span>🎓</span> Student Loans
                          </h3>
                          {liabilities.student.map((loan: any, idx: number) => (
                            <div key={idx} className="border-t border-zinc-800 pt-3 mt-3 first:border-0 first:pt-0 first:mt-0">
                              <div className="flex justify-between text-sm">
                                <span className="text-zinc-400">Servicer</span>
                                <span>{loan.servicer_address?.name || '—'}</span>
                              </div>
                              <div className="flex justify-between text-zinc-400 text-sm">
                                <span>Interest Rate</span>
                                <span className="stat-number">{loan.interest_rate_percentage}%</span>
                              </div>
                              <div className="flex justify-between text-zinc-400 text-sm">
                                <span>Outstanding Balance</span>
                                <span className="stat-number">${loan.outstanding_interest_amount?.toLocaleString() || '—'}</span>
                              </div>
                            </div>
                          ))}
                        </div>
                      )}

                      {(!liabilities || ((!liabilities.credit || liabilities.credit.length === 0) && (!liabilities.student || liabilities.student.length === 0))) && (
                        <div className="text-center py-12 text-zinc-400 bg-zinc-900 rounded-lg border border-[#9C824A]/20">
                          <div className="text-4xl mb-3">🧤</div>
                          <p className="font-medium text-[#9C824A]">No liability data found</p>
                          <p className="text-sm text-zinc-500 mt-1">Clean sheet! 🏆</p>
                        </div>
                      )}
                    </div>
                  )}
                </>
              )}

              {/* Net Worth Tab */}
              {activeTab === 'networth' && (
                <div className="space-y-6">
                  <NetWorthCard />
                </div>
              )}
            </div>
          </>
        )}

        {/* Footer */}
        <footer className="mt-12 pt-6 border-t border-zinc-800">
          <div className="flex flex-col items-center gap-3">
            <p className="flex items-center gap-2 text-sm text-zinc-500">
              <span>Powered by</span>
              <a href="https://plaid.com" target="_blank" rel="noopener noreferrer" className="text-[#9C824A] hover:text-[#EF0107] transition-colors font-medium">Plaid</a>
              <span>•</span>
              <span>Built with</span>
              <a href="https://zo.computer" target="_blank" rel="noopener noreferrer" className="text-[#9C824A] hover:text-[#EF0107] transition-colors font-medium">Zo</a>
            </p>
            <p className="text-zinc-600 text-xs italic">
              "{getArtetaQuote('general')}"
            </p>
          </div>
        </footer>
      </div>
    </div>
  );
}
